// Emit one item per configured source, applying source-provider selection logic.
//
// Provider toggle flags (n8n workflow variables):
//   ENABLE_X=true|false        — Enable/disable X (Twitter) provider.
//                                Requires X_BEARER_TOKEN when true.
//   ENABLE_NEWSAPI=true|false   — Enable/disable NewsAPI provider.
//                                Requires NEWS_API_KEY when true.
//
// If neither flag is set, provider presence is inferred from INTRADAY_SOURCES_JSON
// (backward-compatible behaviour).  Explicit flags take precedence over inferred
// presence when set.
//
// Provider mode behaviour:
//   hybrid       - both X and NewsAPI enabled; all sources used.
//   x_only       - only X enabled; NewsAPI sources excluded.
//   newsapi_only - only NewsAPI enabled; X sources excluded.
//   (error)      - neither enabled; workflow fails with PROVIDER_CONFIG_ERROR.
//
// Sources are read from INTRADAY_SOURCES_JSON (a JSON array of source configs).
// Non-provider source types (rss, api, webhook, social) are always included
// and do not count toward the provider-presence check.
//
// This logic mirrors app/src/utils/sourceProviders.js (source-presence detection)
// and app/src/utils/sourceConfig.js (explicit flag parsing + API key validation).

// ---------------------------------------------------------------------------
// Provider classification helpers (mirrors sourceProviders.js)
// ---------------------------------------------------------------------------

const X_PROVIDER_SOURCE_TYPES = ['x_account', 'x_query'];
const NEWSAPI_SOURCE_TYPE = 'newsapi';

function classifySourceProvider(sourceType) {
  if (X_PROVIDER_SOURCE_TYPES.includes(sourceType)) return 'x';
  if (sourceType === NEWSAPI_SOURCE_TYPE) return 'newsapi';
  return null;
}

function detectProviders(sources) {
  let x = false, newsapi = false;
  for (const s of sources) {
    const p = classifySourceProvider(s && s.type);
    if (p === 'x') x = true;
    if (p === 'newsapi') newsapi = true;
    if (x && newsapi) break;
  }
  return { x, newsapi };
}

function selectSourcesByProviders(sources, providers) {
  return sources.filter(s => {
    const provider = classifySourceProvider(s && s.type);
    if (provider === 'x') return providers.x;
    if (provider === 'newsapi') return providers.newsapi;
    return true;
  });
}

// ---------------------------------------------------------------------------
// Provider flag parsing (mirrors sourceConfig.js)
// ---------------------------------------------------------------------------

function parseProviderFlag(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'string') return value.trim().toLowerCase() === 'true';
  return false;
}

// ---------------------------------------------------------------------------
// Parse INTRADAY_SOURCES_JSON
// ---------------------------------------------------------------------------

const sourcesRaw = $vars.INTRADAY_SOURCES_JSON || '';
let sources;
if (!sourcesRaw || sourcesRaw.trim() === '' || sourcesRaw.trim() === '[]') {
  // No variable set — use the local-dev default source list.
  // NOTE: the defaults contain only rss/api types and will trigger a
  // PROVIDER_CONFIG_ERROR below unless you also set ENABLE_X or ENABLE_NEWSAPI.
  sources = [
    { name: 'CoinDesk RSS',    type: 'rss', url: 'https://www.coindesk.com/arc/outboundfeeds/rss/' },
    { name: 'Reuters Finance', type: 'rss', url: 'https://feeds.reuters.com/reuters/businessNews' },
    { name: 'Ars Technica',    type: 'rss', url: 'https://feeds.arstechnica.com/arstechnica/index' },
    { name: 'Hacker News',     type: 'api', url: 'https://hacker-news.firebaseio.com/v0/topstories.json' }
  ];
} else {
  try {
    sources = JSON.parse(sourcesRaw);
  } catch (e) {
    throw new Error(
      'PROVIDER_CONFIG_ERROR: INTRADAY_SOURCES_JSON is invalid JSON. ' +
      'Fix the variable value before retrying. Parse error: ' + e.message
    );
  }
  if (!Array.isArray(sources)) {
    throw new Error(
      'PROVIDER_CONFIG_ERROR: INTRADAY_SOURCES_JSON must be a JSON array. ' +
      'Received: ' + typeof sources
    );
  }
}

// ---------------------------------------------------------------------------
// Provider validation and mode selection
// ---------------------------------------------------------------------------

// Read explicit provider toggle flags.
const enableXRaw       = $vars.ENABLE_X;
const enableNewsapiRaw = $vars.ENABLE_NEWSAPI;
const flagsExplicit    =
  (enableXRaw !== undefined && enableXRaw !== null && enableXRaw !== '') ||
  (enableNewsapiRaw !== undefined && enableNewsapiRaw !== null && enableNewsapiRaw !== '');

let providers;

if (flagsExplicit) {
  // Explicit flags are set — use them as authoritative, ignoring source presence.
  const enableX       = parseProviderFlag(enableXRaw);
  const enableNewsapi = parseProviderFlag(enableNewsapiRaw);

  if (!enableX && !enableNewsapi) {
    throw new Error(
      'PROVIDER_CONFIG_ERROR: No source providers are enabled. ' +
      'Set ENABLE_X=true and/or ENABLE_NEWSAPI=true. ' +
      'At least one provider must be enabled to run the intraday pipeline.'
    );
  }

  // Validate required API keys for each enabled provider.
  const missing = [];
  if (enableX && !$vars.X_BEARER_TOKEN) {
    missing.push('X_BEARER_TOKEN is required when ENABLE_X=true');
  }
  if (enableNewsapi && !$vars.NEWS_API_KEY) {
    missing.push('NEWS_API_KEY is required when ENABLE_NEWSAPI=true');
  }
  if (missing.length > 0) {
    throw new Error(
      'PROVIDER_CONFIG_ERROR: Missing required API keys.\n' + missing.join('\n')
    );
  }

  providers = { x: enableX, newsapi: enableNewsapi };
} else {
  // No explicit flags — fall back to inferring providers from source presence.
  providers = detectProviders(sources);

  if (!providers.x && !providers.newsapi) {
    throw new Error(
      'PROVIDER_CONFIG_ERROR: No source providers are configured. ' +
      'Add at least one X source (type: x_account or x_query) or ' +
      'one NewsAPI source (type: newsapi) to INTRADAY_SOURCES_JSON, ' +
      'or set ENABLE_X=true and/or ENABLE_NEWSAPI=true.'
    );
  }
}

const providerMode = providers.x && providers.newsapi
  ? 'hybrid'
  : providers.x
    ? 'x_only'
    : 'newsapi_only';

const activeSources = selectSourcesByProviders(sources, providers);

// Log the resolved mode for observability (visible in n8n execution logs).
console.log('[source-ingestion] provider_mode=' + providerMode + ' active_sources=' + activeSources.length + ' flags_explicit=' + flagsExplicit);

return activeSources.map(source => ({ json: source }));

// Parse RSS/Atom XML into source_item objects.
// Uses a simple regex-based approach — replace with a proper XML parser node if available.
// Source metadata (name, url, slug, trust) is read from the 'Is RSS?' node output,
// because the HTTP Request node replaces the item with the response body.
const xml = $input.item.json.data || '';
const sourceConfig = $('Is RSS?').item.json;
const sourceName = sourceConfig.name || 'Unknown RSS';
const sourceUrl = sourceConfig.url || null;
const sourceSlug = sourceConfig.slug || sourceConfig.source_slug || null;
const trustTier = sourceConfig.trust_tier || null;
const trustScore = sourceConfig.trust_score != null ? sourceConfig.trust_score : null;
const fetchedAt = new Date().toISOString();
const items = [];
const itemMatches = xml.matchAll(/<item[^>]*>([\s\S]*?)<\/item>/gi);
for (const match of itemMatches) {
  const block = match[1];
  const getTag = (tag) => {
    const m = block.match(new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${tag}>|<${tag}[^>]*>([^<]*)<\\/${tag}>`, 'i'));
    return m ? (m[1] || m[2] || '').trim() : null;
  };
  const guid = getTag('guid') || getTag('link');
  const title = getTag('title');
  const link = getTag('link');
  const description = getTag('description');
  const pubDate = getTag('pubDate');
  // dc:creator or author for journalist byline
  const author = getTag('dc:creator') || getTag('author') || null;
  if (!guid || !title) continue;
  let published_at = null;
  if (pubDate) {
    const ts = Date.parse(pubDate);
    published_at = !isNaN(ts) ? new Date(ts).toISOString() : null;
  }
  items.push({
    source_id: guid,
    source_slug: sourceSlug,
    source_name: sourceName,
    source_type: 'rss',
    source_url: link || sourceUrl,
    trust_tier: trustTier,
    trust_score: trustScore,
    title: title,
    body: description,
    author: author,
    published_at,
    fetched_at: fetchedAt,
    raw_json: { guid, link, pubDate, description }
  });
}
return items.map(i => ({ json: i }));

// Normalize generic API responses into source_item objects.
// Each source type may need a custom mapping here.
// Source metadata is read from the 'Is X Source?' node output (false branch),
// because the HTTP Request node replaces the item with the response body.
const payload = $input.item.json.data;
const sourceConfig = $('Is X Source?').item.json;
const sourceName = sourceConfig.name || 'Unknown API';
const sourceSlug = sourceConfig.slug || sourceConfig.source_slug || null;
const trustTier = sourceConfig.trust_tier || null;
const trustScore = sourceConfig.trust_score != null ? sourceConfig.trust_score : null;
const fetchedAt = new Date().toISOString();
if (!payload) return [];
// Hacker News returns an array of IDs — emit the first 20 as placeholder items.
if (Array.isArray(payload)) {
  return payload.slice(0, 20).map(id => ({
    json: {
      source_id: String(id),
      source_slug: sourceSlug,
      source_name: sourceName,
      source_type: 'api',
      source_url: `https://news.ycombinator.com/item?id=${id}`,
      title: `HN item ${id}`,
      body: null,
      author: null,
      published_at: null,
      trust_tier: trustTier,
      trust_score: trustScore,
      fetched_at: fetchedAt,
      raw_json: { id }
    }
  }));
}
// Generic object with title/description fields
if (typeof payload === 'object' && payload.title) {
  return [{
    json: {
      source_id: String(payload.id || payload.url || Date.now()),
      source_slug: sourceSlug,
      source_name: sourceName,
      source_type: 'api',
      source_url: payload.url || null,
      title: payload.title,
      body: payload.description || payload.body || null,
      author: payload.author || payload.byline || null,
      published_at: payload.publishedAt || payload.published_at || null,
      trust_tier: trustTier,
      trust_score: trustScore,
      fetched_at: fetchedAt,
      raw_json: payload
    }
  }];
}
return [];

// Build the X API request URL for either x_account or x_query sources.
// x_account: fetch recent tweets from a specific user.
// x_query: search recent tweets matching a query.
//
// Supports both metadata_json and top-level source fields for flexibility.
// For x_account, prefer a numeric X user id stored in metadata and call the
// user tweets endpoint. If only a username is available, fall back to a
// recent search using from:username, which returns tweet objects compatible
// with Parse X Items.
// The actual HTTP fetch is done by the next node.
const source = $input.item.json;

let parsedMetadata = {};
if (source.metadata_json) {
  if (typeof source.metadata_json === 'string') {
    try {
      parsedMetadata = JSON.parse(source.metadata_json);
    } catch (e) {
      parsedMetadata = {};
    }
  } else if (typeof source.metadata_json === 'object') {
    parsedMetadata = source.metadata_json;
  }
}

// Merge top-level fields and metadata_json (metadata_json takes precedence)
const xUserId = (parsedMetadata.x_user_id || source.x_user_id || '').trim();
const xUsername = (parsedMetadata.x_username || source.x_username || '').trim().replace(/^@/, '');
const searchQuery = parsedMetadata.search_query || source.search_query || '';
const rawMaxResults = Number(parsedMetadata.max_results || source.max_results || 10);
const maxResults = Math.min(Number.isFinite(rawMaxResults) ? rawMaxResults : 10, 100);
const tweetFields = 'created_at,public_metrics,author_id';

// Validate username: only allow alphanumeric and underscores (X username rules)
const isValidUsername = (u) => /^[A-Za-z0-9_]{1,15}$/.test(u);

let apiUrl;
if (source.type === 'x_account') {
  if (xUserId && /^\d+$/.test(xUserId)) {
    // Numeric user ID — call the user tweets endpoint directly
    apiUrl = `https://api.twitter.com/2/users/${encodeURIComponent(xUserId)}/tweets?max_results=${maxResults}&exclude=replies,retweets&tweet.fields=${tweetFields}`;
  } else {
    // Username — use recent search with from:username filter
    const username = xUserId || xUsername;
    if (!username) {
      throw new Error('x_account source requires metadata.x_user_id or metadata.x_username');
    }
    if (!isValidUsername(username)) {
      throw new Error(`Invalid X username: ${username}. Must be 1-15 alphanumeric/underscore characters.`);
    }
    const query = encodeURIComponent(`from:${username} -is:reply -is:retweet`);
    apiUrl = `https://api.twitter.com/2/tweets/search/recent?query=${query}&max_results=${maxResults}&tweet.fields=${tweetFields}`;
  }
} else {
  // x_query
  const query = encodeURIComponent(searchQuery);
  apiUrl = `https://api.twitter.com/2/tweets/search/recent?query=${query}&max_results=${maxResults}&tweet.fields=${tweetFields}`;
}

return [{ json: { ...source, x_api_url: apiUrl, x_source_type: source.type } }];

// Parse X API response into source_item objects.
// Handles both user-timeline and search results.
// The X v2 API returns { data: [...tweets], includes: {...} }.
const response = $input.item.json;
const sourceConfig = $('Is X Source?').item.json;
const sourceName = sourceConfig.name || 'Unknown X Source';
const sourceType = sourceConfig.type || 'x_account';
const sourceSlug = sourceConfig.slug || sourceConfig.source_slug || null;
const trustTier = sourceConfig.trust_tier || null;
const trustScore = sourceConfig.trust_score != null ? sourceConfig.trust_score : null;
// Derive the X handle for author attribution (strip leading @ if present)
let parsedMeta = {};
if (sourceConfig.metadata_json) {
  try {
    parsedMeta = typeof sourceConfig.metadata_json === 'string'
      ? JSON.parse(sourceConfig.metadata_json)
      : sourceConfig.metadata_json;
  } catch (_) {}
}
const xHandle = (parsedMeta.x_username || sourceConfig.x_username || '').replace(/^@/, '');
const fetchedAt = new Date().toISOString();

const tweets = response.data?.data || response.data || [];
if (!Array.isArray(tweets) || tweets.length === 0) return [];

return tweets.map(tweet => ({
  json: {
    source_id: `x-${tweet.id}`,
    source_slug: sourceSlug,
    source_name: sourceName,
    source_type: sourceType,
    trust_tier: trustTier,
    trust_score: trustScore,
    source_url: `https://x.com/i/status/${tweet.id}`,
    title: (tweet.text || '').slice(0, 280),
    body: null,
    author: xHandle ? `@${xHandle}` : null,
    published_at: tweet.created_at || null,
    fetched_at: fetchedAt,
    raw_json: {
      id: tweet.id,
      author_id: tweet.author_id || null,
      text: tweet.text || null,
      created_at: tweet.created_at || null,
      public_metrics: tweet.public_metrics || null
    }
  }
}));

// Collect all ingested items and return them as the workflow output.
const items = $input.all().map(i => i.json);
return [{ json: { items } }];
